public class RowColBug {
    public static void main(String[] args) {
        // matrix[row][col]
        int[][] matrix = {{1,2,3},{4,5,6},{7,8,9}};
        // intended: sum of column 0 (1+4+7=12)
        int sum = 0;
        for (int i = 0; i < 3; i++) {
            sum += matrix[0][i];  // bug: iterates row 0 instead of column 0
        }
        System.out.println(sum);
    }
}
